#!/usr/bin/env python3
"""Stop hook (issue 072, task A2).

Runs when a Claude Code session's Stop event fires, from the user project's
CWD (hook-schema-notes.md: hook CWD = ${CLAUDE_PROJECT_DIR}).

Two thin triggers, no reimplementation (plan 072 GC1):
  1. issues/*.md changed since the last sync marker -> invoke
     scripts/project_lifecycle.py --sync as a subprocess.
  2. uncommitted behavior-path changes with no issue linkage -> one
     informational warning line, deduped by fingerprint.

Contract (hook-schema-notes.md, binding):
  - Exit 0 on EVERY path. Exit 2 and decision:"block" are forbidden.
  - stdout carries ONLY the JSON contract (or nothing). All diagnostics go
    to .moduflow/logs/hooks.log.
  - 5-second self-enforced budget; on overrun, log and bail (GC2).
  - Write surface: hooks.log, .moduflow/state/.last-sync,
    .moduflow/state/.linkage-warned, plus whatever --sync writes (GC7).
"""
import hashlib
import importlib.util
import json
import subprocess
import sys
import time
from datetime import datetime, timezone
from pathlib import Path

HOOK_NAME = "on_stop"
SELF_BUDGET_SECONDS = 5.0

# The plugin root is the parent of this file's directory (hooks/..). At
# runtime this is the installed plugin cache, NOT the user's project (GC5).
PLUGIN_ROOT = Path(__file__).resolve().parent.parent

LOG_RELPATH = Path(".moduflow") / "logs" / "hooks.log"
STATE_DIR_RELPATH = Path(".moduflow") / "state"
SYNC_MARKER_RELPATH = STATE_DIR_RELPATH / ".last-sync"
WARN_FINGERPRINT_RELPATH = STATE_DIR_RELPATH / ".linkage-warned"
# Presence of this file means issue-less behavior work was deliberately
# declared; the release gate (075) validates it — out of scope for the
# quick-check, so we stay silent rather than second-guess the declaration.
NO_ISSUE_DECLARATIONS_RELPATH = Path("releases") / "no-issue-declarations.md"

WARNING_PREFIX = "⚠️ 이슈 연결 없는 동작 변경 감지: "
WARNING_SUFFIX = (
    " — product:promote 또는 이슈 브랜치/트레일러 연결 권장 (릴리즈 게이트가 차단함)"
)

_linkage_check = None


def _load_linkage_check(project_root):
    """Import linkage_check by file path (GC1: reuse, never reimplement).

    Preferred copy is the plugin's own scripts/linkage_check.py (sibling of
    hooks/), so the hook works from the installed plugin cache; the project's
    scripts/ copy is the fallback for direct-invocation dogfooding.
    """
    global _linkage_check
    if _linkage_check is not None:
        return _linkage_check
    candidates = [
        PLUGIN_ROOT / "scripts" / "linkage_check.py",
        Path(project_root) / "scripts" / "linkage_check.py",
    ]
    for candidate in candidates:
        if candidate.is_file():
            spec = importlib.util.spec_from_file_location(
                "moduflow_hook_linkage_check", candidate
            )
            module = importlib.util.module_from_spec(spec)
            spec.loader.exec_module(module)
            _linkage_check = module
            return module
    raise FileNotFoundError("linkage_check.py not found (plugin or project scripts/)")


def log_line(project_root, level, message):
    """Append `<iso-ts> on_stop <level> <message>` to hooks.log. Never raises."""
    try:
        path = Path(project_root) / LOG_RELPATH
        path.parent.mkdir(parents=True, exist_ok=True)
        ts = datetime.now(timezone.utc).isoformat()
        message = " ".join(str(message).split())  # keep the log line single-line
        with path.open("a", encoding="utf-8") as fh:
            fh.write(f"{ts} {HOOK_NAME} {level} {message}\n")
    except Exception:
        pass  # logging must never take the hook down


def is_moduflow_project(project_root):
    return (Path(project_root) / ".moduflow" / "state.json").is_file()


def compute_issues_hash(project_root):
    """SHA-256 over the sorted (relpath, mtime_ns, size) list of issues/*.md."""
    issues_dir = Path(project_root) / "issues"
    entries = []
    if issues_dir.is_dir():
        for f in issues_dir.glob("*.md"):
            if not f.is_file():
                continue
            stat = f.stat()
            entries.append((f.name, stat.st_mtime_ns, stat.st_size))
    digest = hashlib.sha256()
    for name, mtime_ns, size in sorted(entries):
        digest.update(f"{name}\t{mtime_ns}\t{size}\n".encode("utf-8"))
    return digest.hexdigest()


def _read_marker(path):
    try:
        return Path(path).read_text(encoding="utf-8").strip()
    except OSError:
        return None


def _write_marker(path, value):
    path = Path(path)
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(value + "\n", encoding="utf-8")


def resolve_lifecycle_script(project_root):
    """Path of project_lifecycle.py to invoke.

    Choice (documented per task A2): prefer the copy shipped next to this
    hook — Path(__file__).parent.parent / "scripts/project_lifecycle.py" —
    because at runtime the hook lives in the installed plugin cache and the
    user's project usually has no scripts/ of its own; fall back to the
    project's copy (ModuFlow repo dogfooding / vendored installs). Either
    way the subprocess runs AGAINST the CWD project, never the plugin repo.
    """
    plugin_copy = PLUGIN_ROOT / "scripts" / "project_lifecycle.py"
    if plugin_copy.is_file():
        return plugin_copy
    project_copy = Path(project_root) / "scripts" / "project_lifecycle.py"
    if project_copy.is_file():
        return project_copy
    return None


def maybe_sync(project_root, deadline):
    """Trigger lifecycle sync when issues/*.md changed since the marker.

    Returns {"synced": bool, "reason": str}. Marker is updated only after a
    successful sync, so a failed sync retries on the next Stop.
    """
    project_root = Path(project_root)
    current = compute_issues_hash(project_root)
    marker_path = project_root / SYNC_MARKER_RELPATH
    if _read_marker(marker_path) == current:
        return {"synced": False, "reason": "unchanged"}

    script = resolve_lifecycle_script(project_root)
    if script is None:
        log_line(project_root, "error", "sync skipped: project_lifecycle.py not found")
        return {"synced": False, "reason": "script-missing"}

    remaining = deadline - time.monotonic()
    if remaining <= 0.2:
        log_line(project_root, "warn", "sync skipped: self budget exhausted")
        return {"synced": False, "reason": "budget"}

    try:
        result = subprocess.run(
            [sys.executable or "python3", str(script), str(project_root), "--sync"],
            cwd=str(project_root),
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            timeout=remaining,
            check=False,
        )
    except subprocess.TimeoutExpired:
        log_line(project_root, "error", "sync subprocess timed out")
        return {"synced": False, "reason": "timeout"}
    except OSError as exc:
        log_line(project_root, "error", f"sync subprocess failed to start: {exc}")
        return {"synced": False, "reason": "spawn-failure"}

    if result.returncode != 0:
        detail = (result.stderr or result.stdout or "").strip()
        log_line(
            project_root,
            "error",
            f"sync exited {result.returncode}: {detail[:300]}",
        )
        return {"synced": False, "reason": "sync-failed"}

    # Re-hash after sync: --sync itself never rewrites issues/*.md, but
    # hashing fresh keeps the marker honest if anything raced.
    _write_marker(marker_path, compute_issues_hash(project_root))
    return {"synced": True, "reason": "issues-changed"}


def _paths_from_porcelain(stdout):
    """Changed paths from `git status --porcelain` output (renames -> new path)."""
    paths = []
    for line in (stdout or "").splitlines():
        if len(line) < 4:
            continue
        entry = line[3:]
        if " -> " in entry:
            entry = entry.split(" -> ", 1)[1]
        entry = entry.strip()
        if entry.startswith('"') and entry.endswith('"'):
            entry = entry[1:-1]
        if entry:
            paths.append(entry)
    return paths


def detect_unlinked(project_root, runner=None, deadline=None):
    """Working-tree linkage quick-check.

    Returns {"unlinked": [paths], "errors": [msgs], "reason": str}.
    Linked when the current branch matches codex/<issue-id>* (linkage_check's
    BRANCH_ISSUE_RE — the working tree has no trailer yet, so the branch is
    the only linkage signal), or a no-issue declaration file is present
    (release gate owns that path).
    """
    project_root = Path(project_root)
    linkage = _load_linkage_check(project_root)
    if runner is None:
        runner = linkage.run_command

    def _timeout():
        if deadline is None:
            return None
        return max(0.2, deadline - time.monotonic())

    # -uall: expand untracked directories into individual files, so a brand
    # new scripts/foo.py surfaces as a concrete path (not "scripts/").
    status = runner(
        ["git", "status", "--porcelain", "-uall"], project_root, timeout=_timeout()
    )
    if status.returncode != 0:
        detail = (status.stderr or status.stdout or "").strip()
        return {
            "unlinked": [],
            "errors": [f"git status --porcelain failed: {detail[:300]}"],
            "reason": "git-error",
        }

    classified = linkage.classify_changed_paths(_paths_from_porcelain(status.stdout))
    behavior = classified["behavior"]
    if not behavior:
        return {"unlinked": [], "errors": [], "reason": "no-behavior-changes"}

    branch = runner(
        ["git", "rev-parse", "--abbrev-ref", "HEAD"], project_root, timeout=_timeout()
    )
    if branch.returncode != 0:
        detail = (branch.stderr or branch.stdout or "").strip()
        return {
            "unlinked": [],
            "errors": [f"git rev-parse --abbrev-ref HEAD failed: {detail[:300]}"],
            "reason": "git-error",
        }
    branch_name = (branch.stdout or "").strip()
    if linkage.BRANCH_ISSUE_RE.match(branch_name):
        return {"unlinked": [], "errors": [], "reason": "codex-branch"}

    if (project_root / NO_ISSUE_DECLARATIONS_RELPATH).is_file():
        return {"unlinked": [], "errors": [], "reason": "no-issue-declaration"}

    return {
        "unlinked": sorted(set(behavior)),
        "errors": [],
        "reason": "unlinked-behavior-changes",
    }


def build_warning(unlinked):
    """One informational line; up to 3 paths, then `+n more` (GC3)."""
    shown = list(unlinked)[:3]
    extra = len(unlinked) - len(shown)
    listing = ", ".join(shown)
    if extra > 0:
        listing += f" +{extra} more"
    return WARNING_PREFIX + listing + WARNING_SUFFIX


def warning_fingerprint(unlinked):
    """SHA-256 of the sorted unlinked path set (Interfaces: .linkage-warned)."""
    canonical = "\n".join(sorted(set(unlinked)))
    return hashlib.sha256(canonical.encode("utf-8")).hexdigest()


def linkage_warning(project_root, deadline=None, runner=None):
    """Warning text to emit, or None. Handles fingerprint dedupe + cleanup."""
    project_root = Path(project_root)
    detection = detect_unlinked(project_root, runner=runner, deadline=deadline)
    for error in detection["errors"]:
        log_line(project_root, "error", error)

    fingerprint_path = project_root / WARN_FINGERPRINT_RELPATH
    unlinked = detection["unlinked"]
    if not unlinked:
        # State resolved (or unknowable): drop the fingerprint so the next
        # occurrence warns again.
        if detection["reason"] != "git-error":
            try:
                fingerprint_path.unlink()
            except FileNotFoundError:
                pass
        return None

    fingerprint = warning_fingerprint(unlinked)
    if _read_marker(fingerprint_path) == fingerprint:
        return None  # same set already warned about — suppress
    _write_marker(fingerprint_path, fingerprint)
    warning = build_warning(unlinked)
    log_line(project_root, "warn", warning)
    return warning


def main():
    start = time.monotonic()
    deadline = start + SELF_BUDGET_SECONDS
    project_root = Path.cwd()

    # Global hook guard: not a ModuFlow project -> total silence, no log spam.
    if not is_moduflow_project(project_root):
        return 0

    try:
        try:
            maybe_sync(project_root, deadline)
        except Exception as exc:  # fail-open per step
            log_line(project_root, "error", f"sync step failed: {exc!r}")

        warning = None
        if time.monotonic() >= deadline:
            log_line(project_root, "warn", "self budget exceeded before linkage check, bailing")
        else:
            try:
                warning = linkage_warning(project_root, deadline=deadline)
            except Exception as exc:
                log_line(project_root, "error", f"linkage step failed: {exc!r}")

        if warning:
            payload = {
                "hookSpecificOutput": {
                    "hookEventName": "Stop",
                    "additionalContext": warning,
                },
                "suppressOutput": True,
            }
            sys.stdout.write(json.dumps(payload, ensure_ascii=False))
            sys.stdout.write("\n")
    except Exception as exc:  # belt and braces: never break the Stop event
        log_line(project_root, "error", f"unhandled: {exc!r}")
    return 0  # ALWAYS 0 — exit 2 / decision:"block" forbidden (schema notes)


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
"""SessionStart hook: inject a compact ModuFlow state banner (issue 072, A1).

Contract (specs/072-lifecycle-hooks-automation/hook-schema-notes.md):
- Runs with CWD = ${CLAUDE_PROJECT_DIR}; resolves the *user project's*
  `.moduflow/` from CWD, never the plugin's own repo (GC5).
- Non-ModuFlow-project guard: no `.moduflow/state.json` under CWD -> emit
  nothing, exit 0, no log spam (delta 3 — plugin hooks are global).
- stdout is reserved for the SessionStart JSON contract only; every
  diagnostic goes to `.moduflow/logs/hooks.log`
  (`<iso-ts> session_start <warn|error> <message>`).
- Exit 0 on every path (fail-open, GC2); 5-second self-enforced budget.
- Banner: <=10 lines Korean-first — 목표, 활성 이슈+phase, 다음 명령,
  막힘 (있을 때만), 미승격 레코드 n건 (있을 때만) (plan.md Interfaces).

Stdlib only.
"""

import json
import sys
import time
from datetime import datetime, timezone
from pathlib import Path

HOOK_NAME = "session_start"
SELF_BUDGET_SECONDS = 5.0
BANNER_MAX_LINES = 10


def append_log(project, level, message):
    """Append one hooks.log line; never raises (logging must not break the hook)."""
    try:
        log_dir = project / ".moduflow" / "logs"
        log_dir.mkdir(parents=True, exist_ok=True)
        ts = datetime.now(timezone.utc).isoformat()
        with open(log_dir / "hooks.log", "a", encoding="utf-8") as fh:
            fh.write("%s %s %s %s\n" % (ts, HOOK_NAME, level, message))
    except Exception:
        pass


def load_json_object(path):
    """Return (dict-or-None, error-or-None). Missing file -> (None, None): not
    an error worth logging. Present-but-unreadable -> (None, message)."""
    try:
        if not path.is_file():
            return None, None
    except OSError as exc:
        return None, "%s stat failed: %s" % (path.name, exc)
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except Exception as exc:
        return None, "%s unreadable: %s" % (path.name, exc)
    if not isinstance(data, dict):
        return None, "%s is not a JSON object" % path.name
    return data, None


def pick(*values):
    for value in values:
        if value:
            return value
    return ""


def unpromoted_record_count(project, deadline):
    """Optional fast source (GC6): retention unpromoted count via
    scripts/project_retention.py — only if importable and within budget.
    Any slowness/error -> None, dropped silently from the banner."""
    try:
        if deadline - time.monotonic() < 0.5:
            return None
        scripts_dir = Path(__file__).resolve().parent.parent / "scripts"
        if not (scripts_dir / "project_retention.py").is_file():
            return None
        if str(scripts_dir) not in sys.path:
            sys.path.insert(0, str(scripts_dir))
        import project_retention

        def budgeted_runner(args, cwd, timeout=10):
            remaining = deadline - time.monotonic()
            if remaining <= 0.1:
                return project_retention.CommandResult(124, "", "hook budget exhausted")
            return project_retention.run_command(
                args, cwd, timeout=min(timeout, remaining)
            )

        status = project_retention.retention_status(project, budgeted_runner)
        if time.monotonic() >= deadline or not status.get("ok"):
            return None
        count = status.get("unpromoted_count")
        return count if isinstance(count, int) else None
    except Exception:
        return None


def build_banner(state, loop, record_count):
    state = state or {}
    loop = loop or {}

    goal = pick(state.get("active_goal"), loop.get("goal_id"), loop.get("objective"))
    issue = pick(state.get("active_issue"), loop.get("active_issue_id"))
    if issue and issue == loop.get("active_issue_id"):
        phase = pick(loop.get("phase"), state.get("phase"))
    else:
        phase = pick(state.get("phase"), loop.get("phase"))
    next_command = pick(state.get("next_command"), loop.get("next_command"))

    blockers = []
    state_blockers = state.get("blockers")
    if isinstance(state_blockers, list):
        blockers.extend(str(b) for b in state_blockers if b)
    loop_blocker = loop.get("blocker")
    if loop_blocker:
        blockers.append(str(loop_blocker))

    lines = ["[ModuFlow] 세션 컨텍스트"]
    if goal:
        lines.append("목표: %s" % goal)
    if issue:
        lines.append("활성 이슈: %s (단계: %s)" % (issue, phase or "?"))
    elif phase:
        lines.append("단계: %s" % phase)
    if next_command:
        lines.append("다음 명령: %s" % next_command)
    if blockers:
        lines.append("막힘: %s" % "; ".join(blockers))
    if record_count:
        lines.append("미승격 레코드: %d건" % record_count)
    return "\n".join(lines[:BANNER_MAX_LINES])


def emit(banner):
    payload = {
        "hookSpecificOutput": {
            "hookEventName": "SessionStart",
            "additionalContext": banner,
        },
        "suppressOutput": True,
    }
    sys.stdout.write(json.dumps(payload, ensure_ascii=False))
    sys.stdout.write("\n")


def main():
    start = time.monotonic()
    deadline = start + SELF_BUDGET_SECONDS

    project = Path.cwd()
    state_path = project / ".moduflow" / "state.json"
    # Non-ModuFlow-project guard: emit nothing, log nothing (schema notes delta 3).
    if not state_path.is_file():
        return

    state, state_err = load_json_object(state_path)
    loop, loop_err = load_json_object(project / "workspace" / "loop-state.json")
    if state_err:
        append_log(project, "warn", state_err)
    if loop_err:
        append_log(project, "warn", loop_err)
    if state is None and loop is None:
        append_log(
            project,
            "error",
            "no readable state (state.json, workspace/loop-state.json); banner skipped",
        )
        return

    if time.monotonic() >= deadline:
        append_log(project, "warn", "self-budget %.0fs exceeded before banner; skipped"
                   % SELF_BUDGET_SECONDS)
        return

    record_count = unpromoted_record_count(project, deadline)
    banner = build_banner(state, loop, record_count)

    if time.monotonic() >= deadline:
        append_log(project, "warn", "self-budget %.0fs exceeded before emit; skipped"
                   % SELF_BUDGET_SECONDS)
        return

    emit(banner)


if __name__ == "__main__":
    try:
        main()
    except Exception as exc:  # fail-open: never block a session (GC2)
        try:
            append_log(Path.cwd(), "error", "unhandled: %r" % (exc,))
        except Exception:
            pass
    sys.exit(0)

#!/usr/bin/env python3
"""Commit-to-issue linkage checking for ModuFlow gates (issue 075, task A1).

Pure importable module: every function takes an injected command runner so
callers (release_check.py, issue 072 hooks, tests) control subprocess access.
Also runnable as a CLI for debugging.

Global Constraint 2 (plan 075): no git subprocess failure is ever swallowed.
Every failure surfaces as an explicit entry in the result dict, and no
function returns a passing/empty result on error.
"""
import argparse
import json
import os
import re
import subprocess
import sys
from dataclasses import dataclass
from pathlib import Path

ISSUE_ID_PATTERN = r"\d{3}-[a-z0-9-]+"
TRAILER_RE = re.compile(rf"^Issue:\s*({ISSUE_ID_PATTERN})\s*$", re.MULTILINE)
BRANCH_ISSUE_RE = re.compile(rf"^codex/({ISSUE_ID_PATTERN})$")

BEHAVIOR_PREFIXES = (
    "scripts/",
    "commands/",
    "skills/",
    "templates/",
    "hooks/",
    ".github/workflows/",
)
BEHAVIOR_FILES = frozenset(
    {
        ".claude-plugin/plugin.json",
        ".codex-plugin/plugin.json",
    }
)

HUMANS_CONFIG_RELPATH = Path(".moduflow") / "humans.json"


@dataclass
class CommandResult:
    returncode: int
    stdout: str
    stderr: str


def _no_prompt_env():
    env = dict(os.environ)
    env["GIT_TERMINAL_PROMPT"] = "0"
    return env


def run_command(args, cwd, timeout=None):
    try:
        result = subprocess.run(
            args,
            cwd=str(cwd),
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False,
            timeout=timeout,
            env=_no_prompt_env(),
        )
    except FileNotFoundError as exc:
        return CommandResult(127, "", str(exc))
    except subprocess.TimeoutExpired:
        suffix = f" after {timeout}s" if timeout else ""
        return CommandResult(124, "", f"git command timed out{suffix}")
    return CommandResult(result.returncode, result.stdout, result.stderr)


def _run(runner, args, cwd):
    return runner(args, cwd)


def _error_text(args, result):
    detail = (result.stderr or "").strip() or (result.stdout or "").strip()
    detail = detail or f"exit code {result.returncode}"
    return f"{' '.join(args)} failed: {detail}"


def _known_issue_ids(runner, cwd, errors):
    """Issue ids from tracked issues/*.md files, used to disambiguate branch
    names such as codex/075-issue-less-context-capture-gate where the trailing
    segment is a work-branch suffix rather than part of the issue id."""
    args = ["git", "ls-files", "issues"]
    result = _run(runner, args, cwd)
    if result.returncode != 0:
        errors.append(_error_text(args, result))
        return []
    ids = []
    for line in (result.stdout or "").splitlines():
        line = line.strip()
        if line.startswith("issues/") and line.endswith(".md"):
            issue_id = line[len("issues/") : -len(".md")]
            if re.fullmatch(ISSUE_ID_PATTERN, issue_id):
                ids.append(issue_id)
    return ids


def _branch_names(runner, cwd, sha, errors):
    names = []
    for args in (
        ["git", "branch", "-r", "--contains", sha],
        ["git", "branch", "--contains", sha],
    ):
        result = _run(runner, args, cwd)
        if result.returncode != 0:
            errors.append(_error_text(args, result))
            continue
        for line in (result.stdout or "").splitlines():
            name = line.strip()
            if name.startswith("* "):
                name = name[2:].strip()
            # "origin/HEAD -> origin/main" style lines
            name = name.split(" -> ")[0].strip()
            if name:
                names.append(name)
    return names


def _issue_id_from_branch(name, known_issue_ids):
    candidates = [name]
    if "/" in name and not name.startswith("codex/"):
        # remote-qualified names, e.g. origin/codex/074-...
        candidates.append(name.split("/", 1)[1])
    for candidate in candidates:
        match = BRANCH_ISSUE_RE.match(candidate)
        if not match:
            continue
        tail = match.group(1)
        best = None
        for issue_id in known_issue_ids:
            if tail == issue_id or tail.startswith(issue_id + "-"):
                if best is None or len(issue_id) > len(best):
                    best = issue_id
        # No known issue id matched: treat the whole tail as the issue id
        # (codex/<issue-id> with no extra suffix).
        return best or tail
    return None


def resolve_issue_for_commit(runner, cwd, sha):
    """Resolve the issue id linked to a commit.

    Returns {sha, issue_id, source, errors} where source is
    'trailer' | 'branch' | None. Trailer wins over branch on conflict
    (Global Constraint 7)."""
    errors = []
    result = {"sha": sha, "issue_id": None, "source": None, "errors": errors}

    show_args = ["git", "show", "-s", "--format=%B", sha]
    show = _run(runner, show_args, cwd)
    if show.returncode != 0:
        errors.append(_error_text(show_args, show))
        return result

    trailer = TRAILER_RE.search(show.stdout or "")
    if trailer:
        result["issue_id"] = trailer.group(1)
        result["source"] = "trailer"
        return result

    branch_names = _branch_names(runner, cwd, sha, errors)
    matched = [n for n in branch_names if _issue_id_from_branch(n, []) is not None]
    if not matched:
        return result

    known_issue_ids = _known_issue_ids(runner, cwd, errors)
    issue_ids = sorted(
        {
            issue_id
            for issue_id in (
                _issue_id_from_branch(name, known_issue_ids) for name in matched
            )
            if issue_id
        }
    )
    if issue_ids:
        result["issue_id"] = issue_ids[0]
        result["source"] = "branch"
    return result


def classify_changed_paths(paths):
    """Split changed paths into behavior vs neutral. Pure function, no git."""
    behavior = []
    neutral = []
    for path in paths:
        path = path.strip()
        if not path:
            continue
        if path in BEHAVIOR_FILES or path.startswith(BEHAVIOR_PREFIXES):
            behavior.append(path)
        else:
            neutral.append(path)
    return {"behavior": behavior, "neutral": neutral}


def _changed_paths_for_commit(runner, cwd, sha, errors):
    args = ["git", "show", "--name-only", "--format=", sha]
    result = _run(runner, args, cwd)
    if result.returncode != 0:
        errors.append(_error_text(args, result))
        return None
    return [line.strip() for line in (result.stdout or "").splitlines() if line.strip()]


def find_unlinked_behavior_commits(runner, cwd, merge_base, head):
    """Check every commit in merge_base..head that touches behavior paths.

    Returns {ok, commits, unlinked, errors}. ok is True only when there are
    no unlinked behavior commits AND no git errors (no silent pass)."""
    errors = []
    commits = []
    unlinked = []

    rev_list_args = ["git", "rev-list", f"{merge_base}..{head}"]
    rev_list = _run(runner, rev_list_args, cwd)
    if rev_list.returncode != 0:
        errors.append(_error_text(rev_list_args, rev_list))
        return {"ok": False, "commits": commits, "unlinked": unlinked, "errors": errors}

    shas = [line.strip() for line in (rev_list.stdout or "").splitlines() if line.strip()]
    for sha in shas:
        paths = _changed_paths_for_commit(runner, cwd, sha, errors)
        if paths is None:
            continue
        classified = classify_changed_paths(paths)
        if not classified["behavior"]:
            continue
        resolution = resolve_issue_for_commit(runner, cwd, sha)
        errors.extend(resolution["errors"])
        entry = {
            "sha": sha,
            "issue_id": resolution["issue_id"],
            "source": resolution["source"],
            "behavior_paths": classified["behavior"],
        }
        commits.append(entry)
        if entry["issue_id"] is None:
            unlinked.append(entry)

    ok = not errors and not unlinked
    return {"ok": ok, "commits": commits, "unlinked": unlinked, "errors": errors}


def _parse_blame_porcelain(text):
    author_name = None
    author_email = None
    for line in (text or "").splitlines():
        if line.startswith("author "):
            author_name = line[len("author ") :].strip()
        elif line.startswith("author-mail "):
            author_email = line[len("author-mail ") :].strip().strip("<>")
    return author_name, author_email


def validate_no_issue_declaration(runner, cwd, file_path, line_no, human_identities):
    """Validate that a declaration line was authored by a configured human.

    Returns {valid, author_name, author_email, reason}. Fails closed: git
    errors, unknown authors, and an empty identity list are all invalid."""
    args = [
        "git",
        "blame",
        "-L",
        f"{line_no},{line_no}",
        "--line-porcelain",
        str(file_path),
    ]
    blame = _run(runner, args, cwd)
    if blame.returncode != 0:
        return {
            "valid": False,
            "author_name": None,
            "author_email": None,
            "reason": _error_text(args, blame),
        }

    author_name, author_email = _parse_blame_porcelain(blame.stdout)
    if not human_identities:
        return {
            "valid": False,
            "author_name": author_name,
            "author_email": author_email,
            "reason": "no configured human identities (.moduflow/humans.json missing or empty)",
        }

    for identity in human_identities:
        name = (identity or {}).get("name")
        email = (identity or {}).get("email")
        if (name and author_name and name == author_name) or (
            email and author_email and email == author_email
        ):
            return {
                "valid": True,
                "author_name": author_name,
                "author_email": author_email,
                "reason": None,
            }

    return {
        "valid": False,
        "author_name": author_name,
        "author_email": author_email,
        "reason": (
            f"blame author {author_name!r} <{author_email}> does not match any "
            "configured human identity"
        ),
    }


def load_human_identities(cwd):
    """Read .moduflow/humans.json. Missing file returns [] — callers must
    treat an empty list as 'no valid declarations possible', never as pass.
    Malformed JSON raises (loud failure, never a silent pass)."""
    config_path = Path(cwd) / HUMANS_CONFIG_RELPATH
    if not config_path.exists():
        return []
    data = json.loads(config_path.read_text(encoding="utf-8"))
    if isinstance(data, list):
        return data
    if isinstance(data, dict) and isinstance(data.get("humans"), list):
        return data["humans"]
    raise ValueError(
        f"{config_path}: expected a JSON list of identities "
        '(or {"humans": [...]})'
    )


def main(argv=None):
    parser = argparse.ArgumentParser(description="ModuFlow commit-to-issue linkage checks (debug CLI).")
    parser.add_argument("--cwd", default=".", help="Repository path (default: current directory).")
    sub = parser.add_subparsers(dest="command", required=True)

    p_resolve = sub.add_parser("resolve", help="Resolve the issue linked to a commit.")
    p_resolve.add_argument("sha")

    p_classify = sub.add_parser("classify", help="Classify paths as behavior/neutral.")
    p_classify.add_argument("paths", nargs="+")

    p_unlinked = sub.add_parser("unlinked", help="Find unlinked behavior commits in merge_base..head.")
    p_unlinked.add_argument("merge_base")
    p_unlinked.add_argument("head")

    p_declare = sub.add_parser("validate-declaration", help="Blame-validate a no-issue declaration line.")
    p_declare.add_argument("file_path")
    p_declare.add_argument("line_no", type=int)

    args = parser.parse_args(argv)
    cwd = Path(args.cwd).resolve()

    if args.command == "resolve":
        result = resolve_issue_for_commit(run_command, cwd, args.sha)
    elif args.command == "classify":
        result = classify_changed_paths(args.paths)
    elif args.command == "unlinked":
        result = find_unlinked_behavior_commits(run_command, cwd, args.merge_base, args.head)
    else:
        identities = load_human_identities(cwd)
        result = validate_no_issue_declaration(
            run_command, cwd, args.file_path, args.line_no, identities
        )

    print(json.dumps(result, ensure_ascii=False, indent=2))
    failed = bool(result.get("errors")) or result.get("ok") is False or result.get("valid") is False
    return 1 if failed else 0


if __name__ == "__main__":
    raise SystemExit(main())

